SELECT id, title, content, author, category, status, create_time, update_time
FROM (
    SELECT t.*, ROWNUM rn
    FROM (
        SELECT id, title, content, author, category, status, create_time, update_time
        FROM t_article
        WHERE status = 1
        ORDER BY create_time DESC
    ) t
    WHERE ROWNUM <= #{offset} + #{limit}
)
WHERE rn > #{offset}

SELECT id, title, content, author, category, status, create_time, update_time
FROM t_article
WHERE status = 1
ORDER BY create_time DESC


        LIMIT #{offset}, #{limit}


        LIMIT #{limit} OFFSET #{offset}






        LIMIT #{offset}, #{limit}
